 1	import type { FC } from 'react';
 2	
 3	import Select from '@components/common/Select';
 4	import MultiTypeaheadSelect from '@components/common/TypeaheadSelect/MultiTypeaheadSelect/MultiTypeaheadSelect';
 5	import type { TypeaheadSelectOption } from '@components/common/TypeaheadSelect/utils/types';
 6	import { Operator } from '@openshift-console/dynamic-plugin-sdk';
 7	import { Button, ButtonVariant, GridItem, TextInput } from '@patternfly/react-core';
 8	import { MinusCircleIcon } from '@patternfly/react-icons';
 9	import { useForkliftTranslation } from '@utils/i18n';
10	
11	import { operatorSelectOptions } from './utils/constants';
12	import type { AffinityLabel } from './utils/types';
13	
14	import './AffinityEditRow.scss';
15	
16	type AffinityEditRowProps = {
17	  expression: AffinityLabel;
18	  onChange: (label: AffinityLabel) => void;
19	  onDelete: (id: number) => void;
20	};
21	
22	const AffinityEditRow: FC<AffinityEditRowProps> = ({ expression, onChange, onDelete }) => {
23	  const { t } = useForkliftTranslation();
24	
25	  const { id, key, operator, values = [] } = expression;
26	  const enableValueField =
27	    operator !== Operator.Exists.valueOf() && operator !== Operator.DoesNotExist.valueOf();
28	
29	  const valueOptions: TypeaheadSelectOption[] = (values ?? []).map((value) => ({
30	    content: value,
31	    value,
32	  }));
33	
34	  return (
35	    <>
36	      <GridItem span={4}>
37	        <TextInput
38	          isRequired
39	          onChange={(_event, newKey) => {
40	            onChange({ ...expression, key: newKey });
41	          }}
42	          placeholder={t('Enter key')}
43	          type="text"
44	          value={key}
45	        />
46	      </GridItem>
47	      <GridItem span={2}>
48	        <Select
49	          id={`affinity-operator-${id}`}
50	          value={operator}
51	          options={operatorSelectOptions}
52	          onSelect={(_ev, selected) => {
53	            const nextOp = String(selected);
54	            // Optional: clear values if switching to unary op to avoid stale state
55	            const nextValues: string[] =
56	              nextOp === Operator.Exists.valueOf() || nextOp === Operator.DoesNotExist.valueOf()
57	                ? []
58	                : values;
59	            onChange({ ...expression, operator: nextOp, values: nextValues });
60	          }}
61	        />
62	      </GridItem>
63	      <GridItem span={5}>
64	        <MultiTypeaheadSelect
65	          className="affinity-edit-row__values-chips"
66	          options={valueOptions}
67	          values={enableValueField ? values : []}
68	          isCreatable
69	          isDisabled={!enableValueField}
70	          placeholder={enableValueField ? t('Enter value') : ''}
71	          // Toggle membership on select
72	          onChange={(nextValues) => {
73	            onChange({ ...expression, values: nextValues as string[] });
74	          }}
75	          // Persist a newly created free-typed value
76	          onCreateOption={(created) => {
77	            if (!values.includes(created)) {
78	              onChange({ ...expression, values: [...values, created] });
79	            }
80	          }}
81	        />
82	      </GridItem>
83	      <GridItem span={1}>
84	        <Button
85	          onClick={() => {
86	            onDelete(id);
87	          }}
88	          variant={ButtonVariant.plain}
89	        >
90	          <MinusCircleIcon />
91	        </Button>
92	      </GridItem>
93	    </>
94	  );
95	};
96	
97	export default AffinityEditRow;

